#{id}
AND c.parent_id <> 0 AND c.status = 1 ORDER BY c.create_time ASC, c.id ASC

SELECT COUNT(1)
FROM tb_product_comment c

    AND c.product_id = #{productId}
    AND c.user_id = #{userId}
    AND c.status = #{status}

        AND c.content LIKE CONCAT('%', #{keyword}, '%')

SELECT c.id AS commentId, c.product_id AS productId, c.sku_id AS skuId, c.user_id AS userId, c.parent_id AS parentId, c.root_id AS rootId, c.rating AS rating, c.content AS content, c.like_count AS likeCount, c.status AS status, c.create_time AS createTime, c.update_time AS updateTime FROM tb_product_comment c
AND c.product_id = #{productId} AND c.user_id = #{userId} AND c.status = #{status}
AND c.content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY c.id DESC LIMIT #{limit} OFFSET #{offset}

